class Solution {
    public int maxTaskAssign(int[] tasks, int[] workers, int pills, int strength) {
        Arrays.sort(tasks);
        Arrays.sort(workers);
        int left = 0, right = Math.min(tasks.length, workers.length);
        while (left < right) {
            int mid = left + (right - left + 1) / 2;
            if (canAssign(tasks, workers, pills, strength, mid)) {
                left = mid;
            } else {
                right = mid - 1;
            }
        }
        return left;
    }

    private boolean canAssign(int[] tasks, int[] workers, int pills, int strength, int numTasks) {
        int n = tasks.length;
        int m = workers.length;
        int taskIndex = n - numTasks;
        for (int i = m - numTasks; i < m; i++) {
            if (workers[i] >= tasks[taskIndex]) {
                taskIndex++;
            } else if (pills > 0 && workers[i] + strength >= tasks[taskIndex]) {
                taskIndex++;
                pills--;
            } else {
                return false;
            }
        }
        return true;
    }
}
